import React, { Component, useEffect } from "react";
import "./App.css";

class Slider extends Component {
  constructor(props) {
    super(props);
    this.state = {
      timer: null,
      photo1: "",
      classNamePhoto: null,
    };
    const photoes = {
      photo1:
        "https://images.unsplash.com/photo-1587620962725-abab7fe55159?ixlib=rb-4.0.3&ixid=MnwxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8&auto=format&fit=crop&w=1631&q=80",
      photo2:
        "https://images.unsplash.com/photo-1587620962725-abab7fe55159?ixlib=rb-4.0.3&ixid=MnwxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8&auto=format&fit=crop&w=1631&q=80",
    };
  }

  render() {
    return (
      <div className="divSlider">
        <img className="photo1" src={this.photo1} alt="programmingPhoto1" />
        <img className="photo2" src={this.photo2} alt="programmingPhoto1" />
      </div>
    );
  }
}
